import os

def generate_lock_file(lock_file_path):
    os.system(f"poetry lock -n && cp poetry.lock {lock_file_path}")

def update_lock_file(lock_file_path):
    os.system(f"poetry update && cp poetry.lock {lock_file_path}")

# To generate a lock file (Poetry lock file)
generate_lock_file("poetry.lock")

# To update the lock file with the latest dependencies
update_lock_file("poetry.lock")